import {
  KeyboardDoubleArrowLeft as PreviousStepIcon,
  KeyboardDoubleArrowRight as NextStepIcon,
} from "@mui/icons-material";
import { MessageAnnouncer, useMessageAnnouncer } from "@textile/common";
import {
  Box,
  Button,
  ButtonProps,
  Step,
  Stepper,
  SxProps,
  Orientation,
} from "@textile/mui";
import {
  Dispatch,
  Fragment,
  FunctionComponent,
  ReactNode,
  SetStateAction,
  createContext,
  useContext,
  useEffect,
  useState,
} from "react";

import { OperationSeverity } from "../common-types";
import { isOperationError } from "../../util/operation-util";

export type OnBeforeWizardNavigate = () => Promise<boolean>;
export type OnWizardNavigateSuccess = (targetStep: string) => void;

export interface WizardState {
  activeStep: string;
  completedSteps: string[];
  disableSubmit: boolean;
  nextStep: string | null;
  onBeforeNext: OnBeforeWizardNavigate | null;
  onBeforePrevious: OnBeforeWizardNavigate | null;
  orientation: Orientation;
  previousStep: string | null;
  setActiveStep: Dispatch<SetStateAction<string>>;
  setCompletedSteps: Dispatch<SetStateAction<string[]>>;
  setDisableSubmit: Dispatch<SetStateAction<boolean>>;
  setNextStep: Dispatch<SetStateAction<string | null>>;
  setOnBeforeNext: Dispatch<SetStateAction<OnBeforeWizardNavigate | null>>;
  setOnBeforePrevious: Dispatch<SetStateAction<OnBeforeWizardNavigate | null>>;
  setPreviousStep: Dispatch<SetStateAction<string | null>>;
}

const WizardContext = createContext<WizardState | null>(null);

export interface WizardProviderProps {
  initialStep: string;
  orientation: Orientation;
  children?: ReactNode;
}

export const WizardProvider: FunctionComponent<WizardProviderProps> = ({
  children,
  initialStep,
  orientation,
}) => {
  const [activeStep, setActiveStep] = useState(initialStep);
  const [completedSteps, setCompletedSteps] = useState<string[]>([]);
  const [nextStep, setNextStep] = useState<string | null>(null);
  const [onBeforeNext, setOnBeforeNext] =
    useState<OnBeforeWizardNavigate | null>(null);
  const [previousStep, setPreviousStep] = useState<string | null>(null);
  const [onBeforePrevious, setOnBeforePrevious] =
    useState<OnBeforeWizardNavigate | null>(null);
  const [disableSubmit, setDisableSubmit] = useState<boolean>(false);

  const wizardStateValue: WizardState = {
    activeStep: activeStep,
    completedSteps,
    disableSubmit,
    nextStep,
    onBeforeNext,
    onBeforePrevious,
    orientation,
    previousStep,
    setActiveStep,
    setCompletedSteps,
    setDisableSubmit,
    setNextStep,
    setOnBeforeNext,
    setOnBeforePrevious,
    setPreviousStep,
  };

  return (
    <WizardContext.Provider value={wizardStateValue}>
      {children}
    </WizardContext.Provider>
  );
};

export const useWizard = () => {
  const wizardState = useContext(WizardContext);

  if (wizardState === null) {
    throw new Error("useWizard cannot be called outside of a WizardContext");
  }

  return wizardState;
};

export interface WizardProps {
  /** Specifies the initial step to set when the wizard is rendered. It determines where the user starts in the wizard process. The value should match one of the defined steps in the wizard. */
  initialStep: string;
  /** Allows you to pass child components that will be rendered within the wizard. These children typically represent the individual steps of the wizard and can include any content that should be displayed for each step. */
  children?: ReactNode;
  /** Allows you to specify the orientation of the wizard. It can be set to `"horizontal"` or `"vertical"` to adjust the layout of the wizard steps. */
  orientation?: Orientation;
}

/**
 * The `Wizard` is a multi-step interface that allows users to navigate through a series of steps in a structured manner.
 * It integrates with `Formik` for form management and validation, and it integrates with a message announcer to provide feedback on navigation actions
 * Useful in applications that require input data across multiple steps.
 *
 * ## Features
 * > - __Dependency on Parent Context__: The component relies on a hook, which must be wrapped in their corresponding parent context providers.
 *    - useMessageAnnouncer
 *
 * - __Customizable Rendering__: Allows for customization of step content and navigation buttons.
 * - __Dynamic Step Management__: Supports dynamic updates to the active step, completed steps, and validation logic, ensuring that the wizard reflects the current state of the form.
 * - __Formik Integration__: Integrates with Formik for management of form state and validation across multiple steps.
 * - __Message Announcer__: It uses a message announcer to provide real-time feedback on navigation success or errors.
 * - __Multi-Step Navigation__: Provides a structured way to navigate through multiple steps.
 *
 * ## Exports
 *
 * #### Components
 * - `Wizard`: Main component that wraps its children in a `WizardProvider`, providing the necessary context for managing wizard state. It initializes the wizard state and renders its children within the context of the wizard.
 * - `WizardContainer`: Provides a layout for the wizard steps, arranging its children based on the orientation of the wizard. It ensures that the steps are displayed in the correct order and orientation.
 * - `WizardProvider`: Provides the wizard context to its children, allowing them to access the wizard state. It manages the state of the wizard, including the active step, completed steps, and callbacks for navigation.
 * - `WizardStepper`: Component renders the stepper for the wizard, displaying the steps and their current status. It provides a visual representation of the wizard's progress, allowing users to see which steps have been completed and which are currently active.
 * - `WizardStep`: Component represents an individual step in the wizard. It manages its active and completed states and renders the content for that step.
 * - `WizardStepContent`: Component provides the content for a specific step in the wizard. It manages the state and updates the wizard context based on the active step.
 * - `WizardNextStepButton`: Component renders a button that allows users to navigate to the next step in the wizard. It handles the navigation logic and integrates with the wizard context.
 * - `WizardPreviousStepButton`: Component renders a button that allows users to navigate to the previous step in the wizard. It handles the navigation logic and integrates with the wizard context.
 * - `WizardSubmitButton`: Component renders a submit button for the wizard. It integrates with the wizard context to manage the submit state.
 *
 * #### Hooks
 * - `useWizard`: Allows components to access the wizard context. Must be wrapped by a `WizardProvider`.
 * - `useWizardOnNavigateNextSuccess`: Provides a callback function that is invoked when navigation to the next step is successful. It updates the completed steps and the active step in the wizard context.
 * - `useWizardOnNavigatePreviousSuccess`: Provides a callback function that is invoked when navigation to the previous step is successful. It updates the completed steps and the active step in the wizard context.
 *
 * #### Interfaces
 * - `WizardProps`: Defines the props that can be passed to the `Wizard` component. It specifies the initial step, orientation, and any child components that will be rendered within the wizard.
 * - `WizardContainerProps`:  Defines the props that can be passed to the `WizardContainer` component. It specifies any child components that will be rendered within the container, providing a layout for the wizard steps.
 * - `WizardProviderProps`: Defines the props that can be passed to the `WizardProvider` component. It specifies the initial step and orientation of the wizard, as well as any child components that will be rendered within the provider.
 * - `WizardState`: Defines the state managed by the wizard context. It includes properties for tracking the active step, completed steps, and various methods for managing the wizard's state.
 * - `WizardStepperProps`:Defines the props that can be passed to the `WizardStepper` component. It specifies any child components that will be rendered within the stepper, typically representing the individual steps of the wizard.
 * - `WizardStepProps`: Defines the props that can be passed to the `WizardStep` component. It specifies the name of the step, its content, and its completion status.
 * - `WizardStepContentProps`: Defines the props that can be passed to the `WizardStepContent` component. It specifies the content displayed for a specific step and manages the state and navigation logic.
 * - `WizardSubmitButtonProps`: Defines the props that can be passed to the `WizardSubmitButton` component. It extends the standard `ButtonProps` to include any additional properties for the submit button.
 *
 *  #### Types
 * - `OnBeforeWizardNavigate`: Defines a function signature for a callback that is invoked before navigating to the next step in the wizar

