  args: {
    initialStep: "step-a",
    children: (
      <>
        <WizardStepper>
          <WizardStep name="step-a">
            <StepLabel>Step A</StepLabel>
          </WizardStep>
          <WizardStep name="step-b">
            <StepLabel>Step B</StepLabel>
          </WizardStep>
          <WizardStep name="step-c">
            <StepLabel>Step C</StepLabel>
          </WizardStep>
        </WizardStepper>
        <WizardStepContent name="step-a" nextStep="step-b">
          <h1>Example Step A Content</h1>
        </WizardStepContent>
        <WizardStepContent
          name="step-b"
          previousStep="step-a"
          nextStep="step-c"
        >
          <h1>Example Step B Content</h1>
        </WizardStepContent>
        <WizardStepContent name="step-c" previousStep="step-b">
          <h1>Example Step C Content</h1>
        </WizardStepContent>
        <Box sx={{ display: "flex", gap: 1 }}>
          <WizardPreviousStepButton />
          <WizardNextStepButton />
        </Box>
      </>
    ),
  },
};

export const HorizontalOrientation: Story = {
  args: {
    ...Primary.args,
    orientation: "horizontal",
  },
  render: Primary.render,
};

export const CompletedSetting: Story = {
  args: {
    ...Primary.args,
    orientation: "horizontal",
    children: (
      <WizardStepper>
        <WizardStep name="step-a" completed>
          <StepLabel>Step A</StepLabel>
        </WizardStep>
        <WizardStep name="step-b">
          <StepLabel>Step B</StepLabel>
        </WizardStep>
        <WizardStep name="step-c" completed>
          <StepLabel>Step C</StepLabel>
        </WizardStep>
      </WizardStepper>
    ),
  },
  render: Primary.render,
};

export const PreviousAndNextStepButtons: Story = {
  args: {
    ...Primary.args,
    children: (
      <>
        <WizardStepper>
          <WizardStep name="step-a">
            <StepLabel>Example Step A</StepLabel>
          </WizardStep>
          <WizardStep name="step-b">
            <StepLabel>Example Step B</StepLabel>
          </WizardStep>
        </WizardStepper>
        <WizardStepContent name="step-a" nextStep="step-b" onBeforeNext={fn()}>
          <h1>Step A Content</h1>
        </WizardStepContent>
        <WizardStepContent
          name="step-b"
          previousStep="step-a"
          onBeforePrevious={fn()}
        >
          <h1>Step B Content</h1>
        </WizardStepContent>
        <Box sx={{ display: "flex", gap: 1 }}>
          <WizardPreviousStepButton />
          <WizardNextStepButton />
        </Box>
      </>
    ),
  },
  render: Primary.render,
};

export const SubmitButton: Story = {
  args: {
    ...Primary.args,
    children: (
      <>
        <WizardStepper>
          <WizardStep name="step-a" completed>
            <StepLabel>Step A</StepLabel>
          </WizardStep>
          <WizardStep name="step-b">
            <StepLabel>Step B</StepLabel>
          </WizardStep>
        </WizardStepper>
        <WizardSubmitButton>Enabled Submit</WizardSubmitButton>
        <WizardSubmitButton disabled={true}>Disabled Submit</WizardSubmitButton>
      </>
    ),
  },
  render: Primary.render,
};

