 the wizard context.
 * - `WizardPreviousStepButton`: Component renders a button that allows users to navigate to the previous step in the wizard. It handles the navigation logic and integrates with the wizard context.
 * - `WizardSubmitButton`: Component renders a submit button for the wizard. It integrates with the wizard context to manage the submit state.
 *
 * #### Hooks
 * - `useWizard`: Allows components to access the wizard context. Must be wrapped by a `WizardProvider`.
 * - `useWizardOnNavigateNextSuccess`: Provides a callback function that is invoked when navigation to the next step is successful. It updates the completed steps and the active step in the wizard context.
 * - `useWizardOnNavigatePreviousSuccess`: Provides a callback function that is invoked when navigation to the previous step is successful. It updates the completed steps and the active step in the wizard context.
 *
 * #### Interfaces
 * - `WizardProps`: Defines the props that can be passed to the `Wizard` component. It specifies the initial step, orientation, and any child components that will be rendered within the wizard.
 * - `WizardContainerProps`:  Defines the props that can be passed to the `WizardContainer` component. It specifies any child components that will be rendered within the container, providing a layout for the wizard steps.
 * - `WizardProviderProps`: Defines the props that can be passed to the `WizardProvider` component. It specifies the initial step and orientation of the wizard, as well as any child components that will be rendered within the provider.
 * - `WizardState`: Defines the state managed by the wizard context. It includes properties for tracking the active step, completed steps, and various methods for managing the wizard's state.
 * - `WizardStepperProps`:Defines the props that can be passed to the `WizardStepper` component. It specifies any child components that will be rendered within the stepper, typically representing the individual steps of the wizard.
 * - `WizardStepProps`: Defines the props that can be passed to the `WizardStep` component. It specifies the name of the step, its content, and its completion status.
 * - `WizardStepContentProps`: Defines the props that can be passed to the `WizardStepContent` component. It specifies the content displayed for a specific step and manages the state and navigation logic.
 * - `WizardSubmitButtonProps`: Defines the props that can be passed to the `WizardSubmitButton` component. It extends the standard `ButtonProps` to include any additional properties for the submit button.
 *
 *  #### Types
 * - `OnBeforeWizardNavigate`: Defines a function signature for a callback that is invoked before navigating to the next step in the wizard.
 * It returns a promise that resolves to a boolean indicating whether the navigation should proceed. This allows for validation or confirmation before moving to the next step.
 * - `OnWizardNavigateSuccess`: Defines a function signature for a callback that is invoked when navigation to a new step is successful. It receives the `targetStep` as a parameter, allowing the application to perform actions based on the new active step.
 */
export const Wizard: FunctionComponent<WizardProps> = ({
  children,
  initialStep,
  orientation = "vertical",
}) => {
  return (
    <WizardProvider initialStep={initialStep} orientation={orientation}>
      {children}
    </WizardProvider>
  );
};

export interface WizardContainerProps {
  children?: ReactNode;
}

export const WizardContainer: FunctionComponent<WizardContainerProps> = ({
  children,
}) => {
  const { orientation } = useWizard();

  const wizardContainerSx: SxProps = {
    display: "flex",
    flexDirection: orientation === "horizontal" ? "column" : "row",
    gap: 2,
  };

  return <Box sx={wizardContainerSx}>{children}</Box>;
};

export interface WizardStepperProps {
  children?: ReactNode;
}

export const WizardStepper: FunctionComponent<WizardStepperProps> = ({
  children,
}) => {
  const { orientation } = useWizard();

  const wizardStepperContainerSx: SxProps = {
    flex: ".5 .5 0px",
  };

  return (
    <Box sx={wizardStepperContainerSx}>
      <Stepper orientation={orientation}>{children}</Stepper>
    </Box>
  );
};

export interface WizardStepProps {
  name: string;
  children?: ReactNode;
  completed?: boolean;
  index?: number;
}

export const WizardStep: FunctionComponent<WizardStepProps> = ({
  name,
  children,
  completed,
  index,
}) => {
  const { activeStep, completedSteps } = useWizard();

  const isStepCompleted = completedSteps.some((step) => {
    return step === name;
  });

  return (
    <Step
      active={name === activeStep}
      completed={isStepCompleted || completed}
      index={index}
    >
      {children}
    </Step>
  );
};

export interface WizardStepContentProps {
  name: string;
  children?: ReactNode;
  disableSubmit?: boolean;
  nextStep?: string | null;
  onBeforeNext?: OnBeforeWizardNavigate;
  onBeforePrevious?: OnBeforeWizardNavigate;
  previousStep?: string | null;
}

export const WizardStepContent: FunctionComponent<WizardStepContentProps> = ({
  name,
  children,
  disableSubmit = false,
  nextStep = null,
  onBeforeNext = null,
  onBeforePrevious = null,
  previousStep = null,
}) => {
  const {
    activeStep,
    setDisableSubmit,
    setNextStep,
    setOnBeforeNext,
    setOnBeforePrevious,
    setPreviousStep,
  } = useWizard();

  const wizardStepContentContainerSx: SxProps = {
    flex: "2 2 0px",
  };

  useEffect(() => {
    if (name === activeStep) {
      setNextStep(nextStep);
      setOnBeforeNext(() => onBeforeNext);
      setPreviousStep(previousStep);
      setOnBeforePrevious(() => onBeforePrevious);
      setDisableSubmit(() => disableSubmit);
    }
  }, [
    activeStep,
    disableSubmit,
    name,
    nextStep,
    onBeforeNext,
    onBeforePrevious,
    previousStep,
    setDisableSubmit,
    setNextStep,
    setOnBeforeNext,
    setOnBeforePrevious,
    setPreviousStep,
  ]);

  return (
    <Fragment>
      {name === activeStep ? (
        <Box sx={wizardStepContentContainerSx}>{children}</Box>
      ) : null}
    </Fragment>
  );
};

const setupWizardNavigation = (
  targetStep: string | null,
  onBeforeNavigate: OnBeforeWizardNavigate | null,
  onNavigateSuccess: OnWizardNavigateSuccess,
  messageAnnouncer: MessageAnnouncer,
) => {
  return async () => {
    if (targetStep) {
      try {
        const continueNavigation = await (onBeforeNavigate?.() ??
          Promise.resolve(true));

        if (continueNavigation === true) {
          onNavigateSuccess(targetStep);
        }
      } catch (error) {
        if (isOperationError(error)) {
          error.operationResult
            .filter(({ severity }) => {
              return severity === OperationSeverity.Error;
            })
            .forEach(({ message }) => {
              messageAnnouncer.error(`Navigation Error: ${message}`);
            });
        } else {
          messageAnnouncer.error(`Navigation Error: ${error}`);
        }
      }
    }
  };
};

export const useWizardOnNavigateNextSuccess = () => {
  const { activeStep, completedSteps, setActiveStep, setCompletedSteps } =
    useWizard();

  const onNavigateSuccess: OnWizardNavigateSuccess = (targetStep) => {
    const updatedCompletedSteps = [...completedSteps, activeStep];

    setCompletedSteps(updatedCompletedSteps);
    setActiveStep(targetStep);
  };

  return onNavigateSuccess;
};

export const WizardNextStepButton = () => {
  const { nextStep, onBeforeNext } = useWizard();
  const onNavigateSuccess = useWizardOnNavigateNextSuccess();
  const messageAnnouncer = useMessageAnnouncer();

  const handleNavigate = setupWizardNavigation(
    nextStep,
    onBeforeNext,
    onNavigateSuccess,
    messageAnnouncer,
  );

  return (
    <Button
      variant="outlined"
      aria-label="Next Step"
      disabled={nextStep === null}
      onClick={handleNavigate}
    >
      <NextStepIcon></NextStepIcon>
    </Button>
  );
};

export const useWizardOnNavigatePreviousSuccess = () => {
  const { completedSteps, previousStep, setActiveStep, setCompletedSteps } =
    useWizard();

  const onNavigateSuccess: OnWizardNavigateSuccess = (targetStep) => {
    const updatedCompletedSteps = completedSteps.filter((step) => {
      return step !== previousStep;
    });

    setCompletedSteps(updatedCompletedSteps);
    setActiveStep(targetStep);
  };

  return onNavigateSuccess;
};

export const WizardPreviousStepButton = () => {
  const { onBeforePrevious, previousStep } = useWizard();
  const onNavigateSuccess = useWizardOnNavigatePreviousSuccess();
