import {
  render,
  renderHook,
  screen,
  waitFor,
  within,
} from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { MessageAnnouncer, MessageAnnouncerProvider } from "@textile/common";
import {
  StepLabel,
  Stepper,
  stepClasses,
  stepLabelClasses,
  stepperClasses,
} from "@textile/mui";
import { mock } from "jest-mock-extended";
import { FunctionComponent, ReactNode, useState } from "react";

import {
  Wizard,
  WizardStepContent,
  WizardNextStepButton,
  WizardPreviousStepButton,
  WizardStep,
  WizardStepper,
  WizardSubmitButton,
  useWizard,
} from "./wizard.component";
import { OperationItem, OperationSeverity } from "../common-types";
import { OperationError } from "../../util/operation-util";

describe("Use Wizard", () => {
  it("throws an error when the Wizard Context is not provided", () => {
    const consoleErrorMock = jest
      .spyOn(console, "error")
      .mockImplementation(jest.fn());

    expect(() => renderHook(() => useWizard())).toThrow(
      Error("useWizard cannot be called outside of a WizardContext"),
    );

    consoleErrorMock.mockRestore();
  });
});

describe("Wizard", () => {
  it("sets the active step to the initial step when created", () => {
    interface ContextWrapperProps {
      children: ReactNode;
    }

    const ContextWrapper: FunctionComponent<ContextWrapperProps> = ({
      children,
    }) => {
      return <Wizard initialStep={activeStep}>{children}</Wizard>;
    };
    const activeStep = "example-step-a";

    const { result } = renderHook(() => useWizard(), {
      wrapper: ContextWrapper,
      initialProps: { initialStep: activeStep },
    });

    expect(result.current.activeStep).toEqual(activeStep);
  });

  describe("Step", () => {
    it("displays the child components", () => {
      render(
        <Wizard initialStep="example-step-a">
          <Stepper>
            <WizardStep name="example-step-a">
              <StepLabel>Example Step A</StepLabel>
            </WizardStep>
            <WizardStep name="example-step-b">
              <StepLabel>Example Step B</StepLabel>
            </WizardStep>
          </Stepper>
        </Wizard>,
      );

      expect(screen.getByText("Example Step A")).toBeInTheDocument();
      expect(screen.getByText("Example Step B")).toBeInTheDocument();
    });

    it("displays the correct step number for each step", () => {
      const { container } = render(
        <Wizard initialStep="example-step-a">
          <Stepper>
            <WizardStep name="example-step-a">
              <StepLabel>Example Step A</StepLabel>
            </WizardStep>
            <WizardStep name="example-step-b">
              <StepLabel>Example Step B</StepLabel>
            </WizardStep>
          </Stepper>
        </Wizard>,
      );

      const matches = container.querySelectorAll(`.${stepClasses.root}`);

      expect(
        within(matches[0] as HTMLElement).getByText("1"),
      ).toBeInTheDocument();
      expect(
        within(matches[1] as HTMLElement).getByText("2"),
      ).toBeInTheDocument();
    });

    it("sets Example Step B to active when the intial step is set to Example Step B", () => {
      render(
        <Wizard initialStep="example-step-b">
          <Stepper>
            <WizardStep name="example-step-a">
              <StepLabel>Example Step A</StepLabel>
            </WizardStep>
            <WizardStep name="example-step-b">
              <StepLabel>Example Step B</StepLabel>
            </WizardStep>
          </Stepper>
        </Wizard>,
      );

      expect(screen.getByText("Example Step A")).not.toHaveClass(
        stepLabelClasses.active,
      );
      expect(screen.getByText("Example Step B")).toHaveClass(
        stepLabelClasses.active,
      );
    });

    it("displays the step as completed when the completed setting is set", () => {
      render(
        <Wizard initialStep="example-step-b">
          <Stepper>
            <WizardStep name="example-step-a" completed>
              <StepLabel>Example Step A</StepLabel>
            </WizardStep>
            <WizardStep name="example-step-b">
              <StepLabel>Example Step B</StepLabel>
            </WizardStep>
          </Stepper>
        </Wizard>,
      );

      expect(screen.getByText("Example Step A")).toHaveClass(
        stepLabelClasses.completed,
      );
      expect(screen.getByText("Example Step B")).not.toHaveClass(
        stepLabelClasses.completed,
      );
    });
  });

  describe("Stepper", () => {
    it("displays the child components", () => {
      render(
        <Wizard initialStep="example-step-a">
          <WizardStepper>
            <WizardStep name="example-step-a">
              <StepLabel>Example Step A</StepLabel>
            </WizardStep>
            <WizardStep name="example-step-b">
              <StepLabel>Example Step B</StepLabel>
            </WizardStep>
          </WizardStepper>
        </Wizard>,
      );

      expect(screen.getByText("Example Step A")).toBeInTheDocument();
      expect(screen.getByText("Example Step B")).toBeInTheDocument();
    });

    it("defaults to vertical orientation when the Wizard orientation is not set", () => {
      const { container } = render(
        <Wizard initialStep="example-step-b">
          <WizardStepper>
            <WizardStep name="example-step-a">
              <StepLabel>Example Step A</StepLabel>
            </WizardStep>
            <WizardStep name="example-step-b">
              <StepLabel>Example Step B</StepLabel>
            </WizardStep>
          </WizardStepper>
        </Wizard>,
      );

      const wizardStepper = container.querySelector(`.${stepperClasses.root}`);

      expect(wizardStepper).toHaveClass(stepperClasses.vertical);
    });

    it("displays a horizontal stepper when the Wizard orientation is set to horizontal", () => {
      const { container } = render(
        <Wizard initialStep="example-step-b" orientation="horizontal">
          <WizardStepper>
            <WizardStep name="example-step-a">
              <StepLabel>Example Step A</StepLabel>
            </WizardStep>
            <WizardStep name="example-step-b">
              <StepLabel>Example Step B</StepLabel>
            </WizardStep>
          </WizardStepper>
        </Wizard>,
      );

      const wizardStepper = container.querySelector(`.${stepperClasses.root}`);

      expect(wizardStepper).toHaveClass(stepperClasses.horizontal);
    });
  });

  describe("Step Content", () => {
    it("displays the content panel when the step is active", () => {
      render(
        <Wizard initialStep="example-step-a">
          <WizardStepper>
            <WizardStep name="example-step-a">
              <StepLabel>Example Step A</StepLabel>
            </WizardStep>
            <WizardStep name="example-step-b">
              <StepLabel>Example Step B</StepLabel>
            </WizardStep>
          </WizardStepper>
          <WizardStepContent name="example-step-a">
            <h1>Example Step A Content</h1>
          </WizardStepContent>
          <WizardStepContent name="example-step-b">
            <h1>Example Step B Content</h1>
          </WizardStepContent>
        </Wizard>,
      );

      expect(screen.getByText("Example Step A Content")).toBeInTheDocument();
    });

    it("does not display the content panel when the step is inactive", () => {
      render(
        <Wizard initialStep="example-step-a">
          <WizardStepper>
            <WizardStep name="example-step-a">
              <StepLabel>Example Step A</StepLabel>
            </WizardStep>
            <WizardStep name="example-step-b">
              <StepLabel>Example Step B</StepLabel>
            </WizardStep>
          </WizardStepper>
          <WizardStepContent name="example-step-a">
            <h1>Example Step A Content</h1>
          </WizardStepContent>
          <WizardStepContent name="example-step-b">
            <h1>Example Step B Content</h1>
          </WizardStepContent>
        </Wizard>,
      );

      expect(
        screen.queryByText("Example Step B Content"),
      ).not.toBeInTheDocument();
    });

    it("updates the next step in the Wizard when the next step changes", async () => {
      const TestWizard = () => {
        const [nextStep, setNextStep] = useState<string | null>(null);

        const handleUpdateStep = () => {
          setNextStep("example-step-b");
        };

        return (
          <MessageAnnouncerProvider>
            <Wizard initialStep="example-step-a">
              <WizardStepper>
                <WizardStep name="example-step-a">
                  <StepLabel>Example Step A</StepLabel>
                </WizardStep>
                <WizardStep name="example-step-b">
                  <StepLabel>Example Step B</StepLabel>
                </WizardStep>
              </WizardStepper>
              <WizardStepContent name="example-step-a" nextStep={nextStep}>
                <h1>Example Step A Content</h1>
              </WizardStepContent>
              <WizardStepContent name="example-step-b">
                <h1>Example Step B Content</h1>
              </WizardStepContent>
              <button onClick={handleUpdateStep}>Update Step</button>
              <WizardNextStepButton></WizardNextStepButton>
            </Wizard>
          </MessageAnnouncerProvider>
        );
      };
      const user = userEvent.setup();

      render(<TestWizard></TestWizard>);

      expect(screen.getByText("Example Step A Content")).toBeInTheDocument();

      const nextButton = screen.getByRole("button", { name: /Next Step/ });

      expect(nextButton).toBeDisabled();
      await user.click(screen.getByRole("button", { name: /Update Step/ }));
      expect(nextButton).toBeEnabled();
      await user.click(nextButton);

      expect(
        await screen.findByText("Example Step B Content"),
      ).toBeInTheDocument();
    });

    it("updates the previous step in the Wizard when the previous step changes", async () => {
      const TestWizard = () => {
        const [previousStep, setPreviousStep] = useState<string | null>(null);

        const handleUpdateStep = () => {
          setPreviousStep("example-step-a");
        };

        return (
          <MessageAnnouncerProvider>
            <Wizard initialStep="example-step-b">
              <WizardStepper>
                <WizardStep name="example-step-a">
                  <StepLabel>Example Step A</StepLabel>
                </WizardStep>
                <WizardStep name="example-step-b">
                  <StepLabel>Example Step B</StepLabel>
                </WizardStep>
              </WizardStepper>
              <WizardStepContent name="example-step-a">
                <h1>Example Step A Content</h1>
              </WizardStepContent>
              <WizardStepContent
                name="example-step-b"
                previousStep={previousStep}
              >
                <h1>Example Step B Content</h1>
              </WizardStepContent>
              <button onClick={handleUpdateStep}>Update Step</button>
              <WizardPreviousStepButton></WizardPreviousStepButton>
            </Wizard>
          </MessageAnnouncerProvider>
        );
      };
      const user = userEvent.setup();

      render(<TestWizard></TestWizard>);

      expect(screen.getByText("Example Step B Content")).toBeInTheDocument();

      const previousButton = screen.getByRole("button", {
        name: /Previous Step/,
      });

      expect(previousButton).toBeDisabled();
      await user.click(screen.getByRole("button", { name: /Update Step/ }));
      expect(previousButton).toBeEnabled();
      await user.click(previousButton);

      expect(
        await screen.findByText("Example Step A Content"),
      ).toBeInTheDocument();
    });

    it("updates the on before next callback in the Wizard when on before next changes", async () => {
      const preventNextStep = jest.fn().mockReturnValue(Promise.resolve(false));
      const allowNextStep = jest.fn().mockReturnValue(Promise.resolve(true));
      const TestWizard = () => {
        const [onBeforeNext, setOnBeforeNext] = useState(() => preventNextStep);

        const handleUpdateNavigationCallback = () => {
          setOnBeforeNext(() => allowNextStep);
        };

        return (
          <MessageAnnouncerProvider>
            <Wizard initialStep="example-step-a">
              <WizardStepper>
                <WizardStep name="example-step-a">
                  <StepLabel>Example Step A</StepLabel>
                </WizardStep>
                <WizardStep name="example-step-b">
                  <StepLabel>Example Step B</StepLabel>
                </WizardStep>
              </WizardStepper>
              <WizardStepContent
                name="example-step-a"
                nextStep="example-step-b"
                onBeforeNext={onBeforeNext}
              >
                <h1>Example Step A Content</h1>
              </WizardStepContent>
              <WizardStepContent name="example-step-b">
                <h1>Example Step B Content</h1>
              </WizardStepContent>
              <button onClick={handleUpdateNavigationCallback}>
                Update Navigation Callback
              </button>
              <WizardNextStepButton></WizardNextStepButton>
            </Wizard>
          </MessageAnnouncerProvider>
        );
      };
      const user = userEvent.setup();

      render(<TestWizard></TestWizard>);

      expect(screen.getByText("Example Step A Content")).toBeInTheDocument();

      const nextButton = screen.getByRole("button", { name: /Next Step/ });

      await user.click(nextButton);

      await waitFor(() => {
