      );
      await user.click(nextButton);

      expect(
        await screen.findByText("Example Step B Content"),
      ).toBeInTheDocument();
      expect(allowNextStep.mock.calls).toHaveLength(1);
    });

    it("updates the on before previous callback in the Wizard when on before previous changes", async () => {
