        );

        const handleUpdateNavigationCallback = () => {
          setOnBeforePrevious(() => allowPreviousStep);
        };

        return (
          <MessageAnnouncerProvider>
            <Wizard initialStep="example-step-b">
              <WizardStepper>
                <WizardStep name="example-step-a">
                  <StepLabel>Example Step A</StepLabel>
                </WizardStep>
                <WizardStep name="example-step-b">
                  <StepLabel>Example Step B</StepLabel>
