    </Button>
  );
};

export const useWizardOnNavigatePreviousSuccess = () => {
  const { completedSteps, previousStep, setActiveStep, setCompletedSteps } =
    useWizard();

  const onNavigateSuccess: OnWizardNavigateSuccess = (targetStep) => {
    const updatedCompletedSteps = completedSteps.filter((step) => {
      return step !== previousStep;
    });

    setCompletedSteps(updatedCompletedSteps);
    setActiveStep(targetStep);
  };

  return onNavigateSuccess;
};

