  title,
  titledBy,
  agGridProps,
  colDefOverrides,
  colGroupDefOverrides,
  rowSelectionMode = "single",
  onSelectionChanged,
  onLinkCellClicked,
  gridPersistOptions,
}) => {
  const theme = useTheme();
  const [agGridApi, setAgGridApi] = useState<GridApi | null>(null);
  const [paginationState, setPaginationState] =
    useState<PaginationChangedEvent | null>(null);
  const [gridSelection, setGridSelection] = useState<IRowNode[] | null>(null);

  // Modules which contain custom cell components.
  const [customCellComponentModules, setCustomCellComponentModules] =
    useState<ModulesType>({});

  const gridTitle = title ?? meta?.title;
  const { textileProps } = useStaticAppContext();
  const { keycloak } = textileProps;

  const gridStateEnabled = useMemo(
    () =>
      !!(
        gridPersistOptions?.enabled &&
        //the key has to be non empty string
        gridPersistOptions?.key?.trim()?.length > 0
      ),
    [gridPersistOptions],
  );

  const gridStateKey = useMemo(() => {
    if (!gridStateEnabled) return undefined;

    const usernamePart = keycloak?.profile?.username ?? "";
    const optionsPart = gridPersistOptions?.key
      ? `${gridPersistOptions.key}`
      : "";

    return `${usernamePart}_${optionsPart}`;
  }, [gridStateEnabled, keycloak, gridPersistOptions]);

  const treeColumn = useMemo(
    () => meta.gridFields.find((field) => field.isTreeColumn),
    [meta],
  );

  const groupColumn = useMemo(
    () =>
      meta.gridFields.find(
        (field) => field.groupField && field.groupField !== "",
      ),
    [meta],
  );

  const treeColumnDef = useMemo((): ColDef => {
    return treeColumn
      ? {
          field: treeColumn.name,
          headerName: treeColumn.header ?? "",
          flex: treeColumn.flex ?? 1,
          autoHeight: treeColumn.wrapText ?? undefined,
          // AG Grid: headerCheckboxSelection is only available if using 'clientSide' rowModelType
          headerCheckboxSelection: meta.pageSize
            ? undefined
            : rowSelectionMode === "multi"
              ? true
              : false,
          checkboxSelection: rowSelectionMode === "multi" ? true : false,
          cellRendererParams: {
            suppressCount: true,
            innerRenderer: treeColumn.cellRenderer
              ? constructCellComponent(
                  customCellComponentModules,
                  treeColumn.cellRenderer,
                )
              : // eslint-disable-next-line @typescript-eslint/no-explicit-any
                (params: any) => params.data[treeColumn.name],
          },
          editable: treeColumn.editable ?? undefined,
          cellEditorParams: {
            innerRenderer: treeColumn.cellEditor
              ? constructCellComponent(
                  customCellComponentModules,
                  treeColumn.cellEditor,
                )
              : // eslint-disable-next-line @typescript-eslint/no-explicit-any
                (params: any) => params.data[treeColumn.name],
          },
        }
      : {};
  }, [treeColumn, meta.pageSize, rowSelectionMode, customCellComponentModules]);

  const getDataPath = useMemo(() => {
    return treeColumn
      ? // eslint-disable-next-line @typescript-eslint/no-explicit-any
        (data: any) => {
          if (!data["tree_data_path"]) {
            // eslint-disable-next-line no-console
            console.warn(
              `DataGrid: Field tree_data_path is missing for data with id: ${data[meta.idField] || "unknown"}`,
            );
          } else {
            return data["tree_data_path"].split("/");
          }
        }
      : undefined;
  }, [treeColumn]);

  // specify which group key to use
  const getServerSideGroupKey = useCallback(
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (dataItem: any) => {
      return dataItem[meta.idField];
    },
    [meta.idField],
  );

  // indicate if row is a group node
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const isServerSideGroup = useCallback((dataItem: any) => {
    return dataItem.group;
  }, []);

  const needToLoadCustomCellComponents = useMemo(() => {
    return (
      meta.gridFields?.find((g) => (g.cellRenderer || g.cellEditor) != null) !=
      null
    );
  }, [meta]);

  // Load custom cell components.
  useEffect(() => {
    // Inspect metadata and see if we need to load custom cell components.
    if (needToLoadCustomCellComponents) {
      const fieldsWithCustomCellComponent = meta.gridFields.filter(
        (field) => field.cellRenderer?.module || field.cellEditor?.module,
      );

      const moduleNames = Array.from(
        new Set(
          fieldsWithCustomCellComponent.map(
            (item) => item.cellRenderer?.module || item.cellEditor?.module,
          ),
        ),
      ) as string[];

      const modulePromises = moduleNames.map((moduleName) =>
        System.import(moduleName),
      );

      getModuleImports(
        moduleNames,
        modulePromises,
        setCustomCellComponentModules,
      );
    }
  }, [meta, needToLoadCustomCellComponents]);

  // Application level data type manager.
  const dataTypeManager = useContext(DataTypeManagerContext);

  // Application-level format manager.
  const appFormatManager = useContext(FormatManagerContext);

  // Callback used to extract the Ag Grid row id from the row data.
  const getRowId = useCallback<GetRowIdFunc>(
    (params: GetRowIdParams) => String(params.data?.[meta.idField]),
    [meta.idField],
  );

  // Construct a format manager by merging the app format manager with the formats passed in with the grid metadata.
  const formatManager = useMemo(() => {
    if (meta.dataTypeFormats) {
      const gridFormats = mapValues(meta.dataTypeFormats, (i) => ({
        format: decodeFormat(i.format),
        nullFormat: decodeFormat(i.nullFormat),
      }));

      return appFormatManager.derive(gridFormats);
    }

    return appFormatManager;
  }, [meta, appFormatManager]);

  const linkCellStyle: LinkCellStyle = useMemo(
    () => ({
      cursor: "pointer",
      color: theme.palette.info.main,
    }),
    [],
  );

  const excelStyles: ExcelStyle[] = useMemo(
    () => [
      {
        id: "header",
        borders: {
          borderBottom: {
            color: theme.palette.common.black,
          },
        },
        font: {
          bold: true,
        },
      },
    ],
    [],
  );

  // Construct the columns.
  const colDefs = useMemo(() => {
    if (groupColumn) {
      return constructColGroupDefs(
        meta,
        rowSelectionMode,
        colGroupDefOverrides,
        dataTypeManager,
        formatManager,
        linkCellStyle,
        customCellComponentModules,
        treeColumn ? true : false,
      );
    } else {
      return constructColDefs(
        meta,
        rowSelectionMode,
        colDefOverrides,
        dataTypeManager,
        formatManager,
        linkCellStyle,
        customCellComponentModules,
        treeColumn ? true : false,
        agGridProps,
      );
    }
  }, [
    groupColumn,
    meta,
    rowSelectionMode,
    colGroupDefOverrides,
    dataTypeManager,
    formatManager,
    customCellComponentModules,
    treeColumn,
    colDefOverrides,
    agGridProps,
  ]);

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  let rowData: any = undefined;
  let rowModelType: "infinite" | "serverSide" | undefined = undefined;
  let pagination: boolean | undefined = undefined;
  let paginationPageSize: number | undefined = undefined;
  let cacheBlockSize: number | undefined = undefined;
  let maxBlocksInCache: number | undefined = undefined;
  let datasource: IDatasource | IServerSideDatasource | undefined = undefined;

  if (data !== null) {
    //IServerSideDataSource (serverSide row model) provided
    if (isAgGridDataSource(data)) {
      datasource = data;
      rowModelType = treeColumn ? "serverSide" : "infinite";
    }

    //in-memory data
    else {
      if (!isDataGridData(data)) {
        throw new Error(
          "Non-paged DataGrid components require their data prop to be of type DataGridData",
        );
      }
      rowData = constructRowData(data);
    }
    if (meta.pageSize && meta.pageSize > 0) {
      pagination = true;
      paginationPageSize = meta.pageSize;
      cacheBlockSize = meta.pageSize;
      maxBlocksInCache = 1;
    }
  }

  const [userGridState, setUserGridState] = useState<UserGridState>();

  const resetAllColumnsToInitialState = useCallback(() => {
    if (gridStateKey && gridStateEnabled && agGridApi) {
      resetUserGridState(gridStateKey);
      agGridApi.setFilterModel(null);

      // Handle both regular columns and grouped columns
      const columnStates: ColumnState[] = [];
      colDefs.forEach((colDef: ColDef | ColGroupDef) => {
        if ((colDef as ColGroupDef).children) {
          // Handle grouped columns
          (colDef as ColGroupDef).children?.forEach((childCol: ColDef) => {
            if (childCol.field) {
              columnStates.push({
                colId: childCol.field,
                width: childCol.width,
                sort: childCol.sort,
                hide: false,
                pinned: null,
              });
            }
          });
        } else if ((colDef as ColDef).field) {
          // Handle regular columns
          columnStates.push({
            colId: (colDef as ColDef).field!,
            width: (colDef as ColDef).width,
            sort: (colDef as ColDef).sort,
            hide: false,
            pinned: null,
          });
        }
      });

      agGridApi.applyColumnState({
        state: columnStates,
        applyOrder: true,
      });
      setUserGridState(undefined);
    }
  }, [gridStateKey, gridStateEnabled, agGridApi, colDefs]);

  const computedUserGridState = useMemo(() => {
    if (!gridStateEnabled || !gridStateKey) return;

    // Retrieve user grid state
    const retrievedUserGridState = getUserGridState(gridStateKey, colDefs, [
      ...(colDefOverrides ?? []),
      ...(colGroupDefOverrides ?? []),
    ]);

    // If no stored state exists, use original column definitions
    if (!retrievedUserGridState) {
      setUserGridState(undefined);
      return undefined;
    }

    // Update auto group column definition if applicable
    if (agGridProps?.autoGroupColumnDef?.field && retrievedUserGridState) {
      // aggrid colId that Aggrid introduces if grid has a tree column for row grouping
      const autoGroupColumnId = "ag-Grid-AutoColumn";

      // Create Maps for fast lookups
      const columnSizingMap = new Map(
        retrievedUserGridState.gridState?.columnSizing?.columnSizingModel.map(
          (size) => [size.colId, size],
        ),
      );
      const sortModelMap = new Map(
        retrievedUserGridState.gridState?.sort?.sortModel.map((sort) => [
          sort.colId,
          sort,
        ]),
      );

      const autoGroupFieldSize = columnSizingMap.get(autoGroupColumnId);
      const autoGroupFieldSort = sortModelMap.get(autoGroupColumnId);

      if (autoGroupFieldSize) {
        //autoGroupColumnDef, ag-Grid will automatically create a column for the grouped data. this column is not part of original columnDefs.
        //separately agGridProps.autoGroupColumnDef is set here based on user preferences, as it is not configured by the coldefs
        agGridProps.autoGroupColumnDef = {
          ...agGridProps.autoGroupColumnDef,
          colId: autoGroupColumnId,
          width: autoGroupFieldSize.width,
          sort: autoGroupFieldSort?.sort,
        };
      }
    }

    setUserGridState(retrievedUserGridState);
    return retrievedUserGridState;
  }, [
    gridStateEnabled,
    gridStateKey,
    colDefs,
    agGridProps,
    colDefOverrides,
    colGroupDefOverrides,
  ]);
  // override the grid header context menu - Reset Columns Action to reset to base grid state as per original meta
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const getMainMenuItems = (params: any) => {
    // Get the default context menu items
    const defaultItems = params?.defaultItems;

    // Create a new array for the context menu items
    const newItems = defaultItems.filter(
      (item: string) => item !== "resetColumns",
    );

    // Add the custom reset action
    newItems.push({
      name: "Reset Columns",
      action: resetAllColumnsToInitialState,
    });
    return newItems;
  };

  //common function to invoke on related user events to save user specific grid column width, visibility, column position, column pinning, row group open, column filter choices
  const saveGridState = useCallback(
    (
      params:
        | ColumnEvent
        | SortChangedEvent
        | (StateUpdatedEvent & { source: string })
        | FilterChangedEvent
        | (RowGroupOpenedEvent & { source: string }),
    ) => {
      if (!gridStateKey) return;
      //only save grid state if the change is triggered by user interaction
      if (
        (!params.source ||
          !(
            params.source.includes("toolPanelUi") ||
            params.source.includes("uiColumnSorted") ||
            params.source.includes("uiColumnMoved") ||
            params.source.includes("autosizeColumns") ||
            params.source.includes("columnMenu") ||
            params.source.includes("filterChanged") ||
            params.source.includes("uiColumnResized")
          )) &&
        !params.type.includes("rowGroupOpened")
      ) {
        return;
      }

      const gridState: GridState = params.api.getState();
      if (gridStateKey && params.source == "rowGroupOpened") {
        const param = params as RowGroupOpenedEvent;
        //if grid is tree grid(row grouped), then save which rows to keep open
        gridState.rowGroupExpansion = {
          expandedRowGroupIds: param.node.expanded
            ? [
                ...(params.api.getState()?.rowGroupExpansion
                  ?.expandedRowGroupIds ?? []),
                ...[param.node.id as string],
              ]
            : [
                ...(params.api
                  .getState()
                  ?.rowGroupExpansion?.expandedRowGroupIds?.filter(
                    (x) => x !== (param.node.id as string),
                  ) ?? []),
              ],
        };
      }
      persistUserGridState(gridStateKey, {
        columnDefs: colDefs,
        gridState: gridState,
      });
    },
    [gridStateKey, colDefs, groupColumn],
  );

  const onAgGridColumnResized = useCallback(
    (event: ColumnResizedEvent) => {
      agGridProps?.onColumnResized?.(event);
      // save user prefered column width
      if (gridStateEnabled) {
        saveGridState(event);
      }
    },
    [agGridProps, gridStateEnabled, saveGridState],
  );

  const onAgGridColumnVisible = useCallback(
    (event: ColumnVisibleEvent) => {
      agGridProps?.onColumnVisible?.(event);
      // save user prefered column visibility
      if (gridStateEnabled) {
        saveGridState(event);
      }
    },
    [agGridProps, gridStateEnabled, saveGridState],
  );

  const onAgGridColumnMoved = useCallback(
    (event: ColumnMovedEvent) => {
      agGridProps?.onColumnMoved?.(event);
      // save user prefered column position
      if (gridStateEnabled) {
        saveGridState(event);
      }
    },
    [agGridProps, gridStateEnabled, saveGridState],
  );

  const onAgGridFilterChanged = useCallback(
    (event: FilterChangedEvent) => {
      agGridProps?.onFilterChanged?.(event);
      // save user prefered column filters
      if (gridStateEnabled) {
        saveGridState(event);
      }
    },
    [agGridProps, gridStateEnabled, saveGridState],
  );

  const onAgGridColumnPinned = useCallback(
    (event: ColumnPinnedEvent) => {
      agGridProps?.onColumnPinned?.(event);
      // save user prefered column pinned
      if (gridStateEnabled) {
        saveGridState(event);
      }
    },
    [agGridProps, gridStateEnabled, saveGridState],
  );

  const onAgGridRowGroupOpened = useCallback(
    (event: RowGroupOpenedEvent) => {
      agGridProps?.onRowGroupOpened?.(event);
      // save user prefered row group state
      if (gridStateEnabled) {
        saveGridState({ ...event, source: event.type });
      }
    },
    [agGridProps, gridStateEnabled, saveGridState],
  );

  const onAgGridStateUpdated = useCallback(
    (event: StateUpdatedEvent) => {
      agGridProps?.onStateUpdated?.(event);
      // save user prefered column state
      if (gridStateEnabled) {
        saveGridState({ ...event, source: event.type });
      }
    },
    [agGridProps, gridStateEnabled, saveGridState],
  );

  const onAgGridReady = useCallback(
    (event: GridReadyEvent) => {
      agGridProps?.onGridReady?.(event);
      setAgGridApi(event.api);
    },
    [agGridProps],
  );

  const onAgGridSelectionChanged = useCallback(
    (event: SelectionChangedEvent<unknown>) => {
      // First call original onSelectionChanged if any.
      agGridProps?.onSelectionChanged?.(event);

      setGridSelection(event.api.getSelectedNodes());
      onSelectionChanged?.(event.api.getSelectedNodes().map((r) => r.data));
    },
    [agGridProps, onSelectionChanged],
  );

  const onAgGridCellClicked = useCallback(
    (event: CellClickedEvent) => {
      // First call original onCellClicked if any.
      agGridProps?.onCellClicked?.(event);

      // Check if the current cell is a clickable link.
      // If yes, call the onLinkCellClicked callback.
      const gridField = meta.gridFields.find(
        (f) => f.name === event.colDef.field,
      );

      if (
        gridField !== undefined &&
        event.rowIndex != null &&
        (gridField.isLink ||
          (gridField.isLinkField && event.data[gridField.isLinkField]))
      ) {
        onLinkCellClicked?.(gridField.name, event.rowIndex, event.data);
      }
    },
    [agGridProps, meta.gridFields, onLinkCellClicked],
  );

  const onAgGridSortChanged = useCallback(
    (event: SortChangedEvent) => {
      // First call original onSortChanged if any.
      agGridProps?.onSortChanged?.(event);

      const columnState = event.api.getColumnState();
      const sortDefs: SortDef[] = columnState
        .filter((column) => column.sort != null)
        .sort(
          (column1, column2) =>
            (column1.sortIndex ?? 0) - (column2.sortIndex ?? 0),
        )
        .map<SortDef>((column) => ({
          field: column.colId ?? "",
          direction: column.sort === "asc" ? "asc" : "desc",
        }))
        .filter((sd) => sd.field != "");

      onSortChanged?.(sortDefs);
    },
    [agGridProps, onSortChanged],
  );

  const newAgGridProps: AgGridReactProps = useMemo(
    () => ({
      ...agGridProps,
      onSelectionChanged: onAgGridSelectionChanged,
      onCellClicked: onAgGridCellClicked,
      onGridReady: onAgGridReady,
      onSortChanged: (e) => {
        onAgGridSortChanged(e);
        //binding events to save user specific grid sort choices if enabled
        if (gridStateEnabled) {
          saveGridState(e);
        }
      },
      defaultCsvExportParams: {
        ...(gridTitle
          ? {
              fileName: `${gridTitle.replaceAll(" ", "_")}_${crypto.randomUUID()}.csv`,
            }
          : {}),
        ...(agGridProps?.defaultCsvExportParams ?? {}),
      },
      defaultExcelExportParams: {
        ...(gridTitle
          ? {
              fileName: `${gridTitle.replaceAll(" ", "_")}_${crypto.randomUUID()}.xlsx`,
            }
          : {}),
        ...(agGridProps?.defaultExcelExportParams ?? {}),
      },
      onColumnResized: onAgGridColumnResized,
      onColumnVisible: onAgGridColumnVisible,
      onColumnMoved: onAgGridColumnMoved,
      onColumnPinned: onAgGridColumnPinned,
      onRowGroupOpened: onAgGridRowGroupOpened,
      onStateUpdated: onAgGridStateUpdated,
      onFilterChanged: onAgGridFilterChanged,
    }),
    [
      agGridProps,
      onAgGridSelectionChanged,
      onAgGridCellClicked,
      onAgGridReady,
      onAgGridSortChanged,
      saveGridState,
      gridStateEnabled,
      onAgGridColumnResized,
      onAgGridColumnVisible,
      onAgGridColumnMoved,
      onAgGridColumnPinned,
      onAgGridRowGroupOpened,
      onAgGridStateUpdated,
      onAgGridFilterChanged,
    ],
  );

  agGridApi?.setGridAriaProperty("label", title ?? meta.title ?? null);
  agGridApi?.setGridAriaProperty("labelledby", titledBy ?? null);

  const dataGridPaginationProps = useMemo<DataGridPaginationState>(
    () => ({ paginationState, gridSelection, onAgGridSelectionChanged }),
    [paginationState, gridSelection, onAgGridSelectionChanged],
  );

  const handlePaginationChanged = useCallback(
    (event: PaginationChangedEvent) => setPaginationState(event),
    [],
  );

  const effectiveColumnDefs = useMemo(() => {
    return gridStateEnabled &&
      userGridState?.columnDefs &&
      userGridState?.columnDefs?.length > 0
      ? userGridState.columnDefs
      : colDefs;
  }, [gridStateEnabled, userGridState, colDefs]);

  return meta.idField === "dummy_id_field" ||
    (needToLoadCustomCellComponents && isEmpty(customCellComponentModules)) ? (
    <EmptyAgGridReact />
  ) : (
    <DataGridPaginationStateContextProvider {...dataGridPaginationProps}>
      <AgGridReact
        className="ag-theme-alpine"
        getMainMenuItems={getMainMenuItems}
        onPaginationChanged={handlePaginationChanged}
        columnDefs={effectiveColumnDefs}
        initialState={computedUserGridState?.gridState}
        tooltipShowDelay={500}
        defaultColDef={defaultColDef}
        rowModelType={rowModelType}
        pagination={pagination}
        paginationPageSize={paginationPageSize}
        cacheBlockSize={cacheBlockSize}
        maxBlocksInCache={maxBlocksInCache}
        rowData={rowData}
        datasource={
          rowModelType == "serverSide" ? undefined : (datasource as IDatasource)
        }
        serverSideDatasource={datasource as IServerSideDatasource}
        getRowId={meta.idField ? getRowId : undefined}
        rowSelection={rowSelectionMode === "multi" ? "multiple" : "single"}
        suppressRowClickSelection={false}
        autoGroupColumnDef={treeColumnDef}
        treeData={treeColumn ? true : undefined}
        // AG Grid: group selects children is NOT supported for Server Side Row Model.
        // This is because the rows are lazy loaded, so selecting a group is not possible
        // as the grid has no way of knowing what the children are.
        groupSelectsChildren={treeColumn && !meta.pageSize ? true : undefined}
        getDataPath={getDataPath}
        isServerSideGroup={isServerSideGroup}
        getServerSideGroupKey={getServerSideGroupKey}
        embedFullWidthRows={agGridProps?.masterDetail}
        excelStyles={excelStyles}
        {...newAgGridProps}
      />
    </DataGridPaginationStateContextProvider>
  );
};

/*
 * Convert an order expression to an array of SortDefs.
 */
const orderByExpressionToSortDefs = (orderByExpression?: string) => {
  let sortDefs: SortDef[] = [];
  if (orderByExpression) {
    sortDefs = orderByExpression
      .split(",")
      .map((fd) => fd.trim())
      .map((fd) => {
        const parts = fd.split(" ").map((p) => p.trim());
        return {
          field: parts[0],
          direction: parts[1] === "desc" ? "desc" : "asc",
        };
      });
  }

  return sortDefs;
};

const constructCellComponent = (
  customCellComponentModules: ModulesType,
  fieldCellComponent?: CustomCellComponent,
) => {
  if (
    fieldCellComponent &&
    customCellComponentModules?.[fieldCellComponent.module]
  ) {
    const Cmp =
      customCellComponentModules[fieldCellComponent.module][
        fieldCellComponent.component
      ];

    if (!Cmp) {
      // eslint-disable-next-line no-console
      console.warn(
        `DataGrid: Component ${fieldCellComponent.component} is missing from module ${fieldCellComponent.module}`,
      );
      return undefined;
    }

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    return (props: any) => (
      <div className="cell-component-wrapper ag-cell-value">
        <Cmp {...props} {...fieldCellComponent.props} />
      </div>
    );
  } else {
    return undefined;
  }
};

const constructHeaderClass = (field: DataGridField) => {
  const headerClass = [];
  const numberDataTypes = ["currency", "rate", "int", "float", "percent"];

  if (numberDataTypes.includes(field.dataType)) {
    headerClass.push("text-align-right");
  }

  if (field.wrapHeaderText) {
    headerClass.push("multiline-ellipses");
  }
  if (field.headerClass) {
    headerClass.push(field.headerClass);
  }

  return headerClass;
};

/**
 * Given a DataGrid metadata, construct AgGrid column definitions.
 */
const constructColDefs = (
  meta: DataGridMeta,
  rowSelection: "single" | "multi",
  colDefOverrides: ColDefOverride[] | undefined,
  dataTypeManager: DataTypeManager,
  formatManager: FormatManager,
  linkCellStyle: LinkCellStyle,
  customCellComponentModules: ModulesType,
  isTreeColumn: boolean,
  agGridProps?: AgGridReactProps,
) => {
  const colDefs: ColDef[] = [];
  let firstColumn = true;

  const initialSortDefs = orderByExpressionToSortDefs(meta.initialOrderBy);
  const isMultiSelectGrid = rowSelection === "multi" && !isTreeColumn;
  const isMasterDetailConfigured = isTreeColumn
    ? undefined
    : agGridProps?.masterDetail &&
      (agGridProps?.detailCellRendererParams ||
        agGridProps?.detailCellRenderer);
  for (const field of meta.gridFields) {
    // Show fields, unless visible is explicitly set to false.
    if (field.visible) {
      const colDefOverride = colDefOverrides?.find(
        (cdo) => cdo.field === field.name,
      );
      const fieldData = extractCommonFieldDetail(
        field,
        meta,
        formatManager,
        dataTypeManager,
        initialSortDefs,
        customCellComponentModules,
        linkCellStyle,
      );
      const colDef: ColDef = {
        ...fieldData,
        ...colDefOverride?.colDef,
      };

      // Ensuring that quickfilter for DataGrid works even when colDefOverride has a valueFormatter
      if (colDefOverride?.colDef?.valueFormatter) {
        colDef.getQuickFilterText = colDefOverride?.colDef?.valueFormatter as (
          params: GetQuickFilterTextParams<unknown>,
        ) => string;
      }

      if (firstColumn) {
        if (isMasterDetailConfigured) {
          colDef.cellRenderer = "agGroupCellRenderer";
        }
      }
      firstColumn = false;
      colDefs.push(colDef);
    }
  }

  //Extra checkbox column is not needed in the case of row grouping
  const hasRowGroup = colDefOverrides?.find((cdo) => cdo.colDef.rowGroup)
    ? true
    : false;

  if (isMultiSelectGrid && !hasRowGroup) {
    addCheckboxColumn(colDefs, colDefOverrides);
  }

  return colDefs;
};

const extractCommonFieldDetail = (
  field: DataGridField,
  meta: DataGridMeta,
  formatManager: FormatManager,
  dataTypeManager: DataTypeManager,
  initialSortDefs: SortDef[],
  customCellComponentModules: ModulesType,
  linkCellStyle: LinkCellStyle,
) => {
  const getMetaLevelFormatObj = memoize(
    (cellLevelDataType?: string): FormatObj => {
      const dataType = cellLevelDataType ?? field.dataType;
      // Get the merged app + grid format for the column type.
      const appGridFormat = formatManager.getFormat(dataType);

      // If column level formatting is present, override the app + grid format.
      return merge({}, appGridFormat.format, decodeFormat(field.format));
    },
  );

  // Memoized lambda to calculate the metadata-based null format object.
  // If cellLevelDataType is passed in, use that as the data type when determining the base format,
  // otherwise use the field type passed in with the field metadata.
  const getMetaLevelNullFormatObj = memoize(
    (cellLevelDataType?: string): FormatObj => {
      const dataType = cellLevelDataType ?? field.dataType;

      // Get the merged app + grid format for the column type.
      const appGridFormat = formatManager.getFormat(dataType);

      // If column level formatting is present, override the app + grid format.
      return merge(
        {},
        appGridFormat.nullFormat,
        decodeFormat(field.nullFormat),
      );
    },
  );
  const baseType = dataTypeManager.getBaseType(field.dataType);

  // If the field type is a derivative of float and its format is for a percent
  // add a percent sign to the header.
  const addPercentSignToHeaderName =
    baseType === "float" &&
    isPercentByTextFormat(
      formatManager.getFormat(field.dataType).format.format,
    );

  const headerName = `${field.header}${addPercentSignToHeaderName ? " %" : ""}`;
  // Turn off client-side sorting for paged grids.
  const comparator = meta.pageSize ? serverColumnComparator : undefined;
  // Note that we coalesce all falsy width values (including 0) the same as undefined.
  const width = field.width ? field.width : undefined;
  // If no width or flex is defined, default to flex 1.
  const flex = field.flex ? field.flex : field.width ? undefined : 1;
  const valueFormatter = constructFormatterFunction({
    columnBaseType: baseType,
    cellLevelDataTypeField: field.dataTypeField,
    rowLevelFormatField: meta.formatField,
    rowLevelNullFormatField: meta.nullFormatField,
    cellLevelFormatField: field.formatField,
    cellLevelNullFormatField: field.nullFormatField,
    getMetaLevelFormatObj,
    getMetaLevelNullFormatObj,
    dataTypeManager,
  });
  const getQuickFilterText = (params: GetQuickFilterTextParams<unknown>) => {
    if (field.dataType === "date") {
      const value = valueFormatter?.(params);
      return value;
    }
    return params.value;
  };
  const cellStyle = constructCellStyleFunction(
    {
      cellLevelDataTypeField: field.dataTypeField,
      rowLevelFormatField: meta.formatField,
      rowLevelNullFormatField: meta.nullFormatField,
      cellLevelFormatField: field.formatField,
      cellLevelNullFormatField: field.nullFormatField,
      columnLevelIsLink: field.isLink,
      cellLevelIsLinkField: field.isLinkField,
      getMetaLevelFormatObj,
      getMetaLevelNullFormatObj,
    },
    linkCellStyle,
  );
  const cellRenderer = constructCellComponent(
    customCellComponentModules,
    field.cellRenderer,
  );

  const cellEditor = constructCellComponent(
    customCellComponentModules,
    field.cellEditor,
  );

  const headerClass = constructHeaderClass(field);
  // Is this column sorted?
  const fieldIndex = initialSortDefs.findIndex(
    (sortDef) => sortDef.field === field.name,
  );
  //spanning a cell based on spanField data provided
  const colSpan = field.spanField
    ? // eslint-disable-next-line @typescript-eslint/no-explicit-any
      (params: any) => {
        const key = field.spanField as keyof typeof params.data;
        const spanValue = params.data?.[key];
        return Number.isInteger(spanValue) && spanValue > 0 ? spanValue : 1;
      }
    : undefined;

  return {
    cellEditor,
    cellRenderer,
    cellStyle,
    valueFormatter,
    getQuickFilterText,
    comparator,
    editable: field.editable ?? undefined,
    headerClass,
    width,
    flex,
    headerName,
    colSpan,
    field: field.name,
    sort: fieldIndex != -1 ? initialSortDefs[fieldIndex].direction : null,
    sortIndex: fieldIndex != -1 ? fieldIndex : null,
    wrapText: field.wrapText ?? undefined,
    autoHeight: field.wrapText ?? undefined,
    headerTooltip: field.header ?? undefined,
    wrapHeaderText: field.wrapHeaderText ?? undefined,
    autoHeaderHeight:
      field.autoHeaderHeight ?? field.wrapHeaderText ?? undefined,
    resizable: field.resizable ?? undefined,
    minWidth: field.minWidth ?? undefined,
  };
};
//Column Def for groups
const constructColGroupDefs = (
  meta: DataGridMeta,
  rowSelection: "single" | "multi",
  colDefOverrides: ColGroupDefOverride[] | undefined,
  dataTypeManager: DataTypeManager,
  formatManager: FormatManager,
  linkCellStyle: LinkCellStyle,
  customCellComponentModules: ModulesType,
  isTreeColumn: boolean,
) => {
  const colDefs: (ColDef | ColGroupDef)[] = [];
  const initialSortDefs = orderByExpressionToSortDefs(meta.initialOrderBy);
  const isMultiSelectGrid = rowSelection === "multi" && !isTreeColumn;
  for (const field of meta.gridFields) {
    // Show fields, unless visible is explicitly set to false.
    //Grouping columns based on groupField meta property
    if (field.visible && (!field.groupField || field.groupField === "")) {
      const colDefOverride = colDefOverrides?.find(
        (cdo) => cdo.field === field.name,
      );
      const groupFieldData = extractCommonFieldDetail(
        field,
        meta,
        formatManager,
        dataTypeManager,
        initialSortDefs,
        customCellComponentModules,
        linkCellStyle,
      );
      const childColumns = meta.gridFields.filter(
        (cdo) => cdo.groupField === field.name,
      );
      let colDef: ColDef | ColGroupDef = {
        ...groupFieldData,
        ...colDefOverride?.colDef,
      };
      if (childColumns.length > 0) {
        const childArray: ColDef[] = [];
        childColumns.forEach((item: DataGridField) => {
          const childFieldData = extractCommonFieldDetail(
            item,
            meta,
            formatManager,
            dataTypeManager,
            initialSortDefs,
            customCellComponentModules,
            linkCellStyle,
          );
          childArray.push({
            ...childFieldData,
          });
        });
        colDef = { children: childArray, ...colDef };
      }
      colDefs.push(colDef);
    }
  }

  //Extra checkbox column is not needed in the case of row grouping
  if (isMultiSelectGrid) {
    addCheckboxColumn(colDefs, colDefOverrides);
  }
  return colDefs;
};

const addCheckboxColumn = (
  colDefs: (ColDef | ColGroupDef)[],
  colDefOverrides?: (ColDefOverride | ColGroupDefOverride)[] | undefined,
) => {
  const defaultCheckBoxColumnDef: ColDef | ColGroupDef = {
    field: "checkbox",
    headerName: "",
    checkboxSelection: true,
    resizable: false,
    maxWidth: 26, // Set the maximum width of the checkbox column
    suppressSizeToFit: true,
    cellStyle: {
      padding: "6px 4px",
      justifyContent: "center",
      display: "flex",
      margin: "0px",
    },
    cellClass: "custom-checkbox-cell",
    headerComponent: DataGridSelectAllCheckBox,
  };

  const colDefOverride = colDefOverrides?.find(
    (cdo) => cdo.field === "checkbox",
  );

  const checkBoxColumnDef = {
    ...defaultCheckBoxColumnDef,
    ...(colDefOverride?.colDef || {}),
  };

  colDefs.unshift(checkBoxColumnDef);
};
/**
 * Given a DataGrid data prop, construct AgGrid row data.
 */
const constructRowData = (data: DataGridData) => {
  return data.rowData;
};

/**
 * Construct a column's formatter function.
 */
const constructFormatterFunction = ({
  columnBaseType,
  cellLevelDataTypeField,
  rowLevelFormatField,
  rowLevelNullFormatField,
  cellLevelFormatField,
  cellLevelNullFormatField,
  getMetaLevelFormatObj,
  getMetaLevelNullFormatObj,
  dataTypeManager,
}: {
  columnBaseType: string;
  cellLevelDataTypeField?: string;
  rowLevelFormatField?: string;
  rowLevelNullFormatField?: string;
  cellLevelFormatField?: string;
  cellLevelNullFormatField?: string;
  getMetaLevelFormatObj: ((cellLevelDataType?: string) => FormatObj) &
    MemoizedFunction;
  getMetaLevelNullFormatObj: ((cellLevelDataType?: string) => FormatObj) &
    MemoizedFunction;
  dataTypeManager: DataTypeManager;
}): ValueFormatterFunc | undefined => {
  const metaLevelFormat = formatFunction(
    columnBaseType,
    getMetaLevelFormatObj(undefined),
    getMetaLevelNullFormatObj(undefined),
  );

  // Memoize the function generated by calling formatFunction.
  // This will prevent generation of this function for every cell when we need
  // to install row-level and cell-level formatting.
  const cellLevelFormatFunction = memoize(
    formatFunction,
    (type, formatObj, nullFormatObj) =>
      (type || "") +
      "|" +
      (formatObj?.format || "") +
      "|" +
      (nullFormatObj?.format || ""),
  );

  if (
    cellLevelDataTypeField ||
    rowLevelFormatField ||
    rowLevelNullFormatField ||
    cellLevelFormatField ||
    cellLevelNullFormatField
  ) {
    return (params) => {
      if (
        (cellLevelDataTypeField && params.data?.[cellLevelDataTypeField]) ||
        (rowLevelFormatField && params.data?.[rowLevelFormatField]) ||
        (rowLevelNullFormatField && params.data?.[rowLevelNullFormatField]) ||
        (cellLevelFormatField && params.data?.[cellLevelFormatField]) ||
        (cellLevelNullFormatField && params.data?.[cellLevelNullFormatField])
      ) {
        const formatObj = merge(
          {},
          getMetaLevelFormatObj(
            cellLevelDataTypeField
              ? params.data[cellLevelDataTypeField]
              : undefined,
          ),
          decodeFormat(
            rowLevelFormatField ? params.data[rowLevelFormatField] : undefined,
          ),
          decodeFormat(
            cellLevelFormatField
              ? params.data[cellLevelFormatField]
              : undefined,
          ),
        );

        const nullFormatObj = merge(
          {},
          getMetaLevelNullFormatObj(
            cellLevelDataTypeField
              ? params.data[cellLevelDataTypeField]
              : undefined,
          ),
          decodeFormat(
            rowLevelNullFormatField
              ? params.data[rowLevelNullFormatField]
              : undefined,
          ),
          decodeFormat(
            cellLevelFormatField
              ? params.data[cellLevelFormatField]
              : undefined,
          ),
        );

        const baseType = (
          cellLevelDataTypeField
            ? params.data[cellLevelDataTypeField]
            : undefined
        )
          ? dataTypeManager.getBaseType(
              cellLevelDataTypeField
                ? params.data[cellLevelDataTypeField]
                : undefined,
            )
          : columnBaseType;

        const cellLevelFormat = cellLevelFormatFunction(
          baseType,
          formatObj,
          nullFormatObj,
        );

        return cellLevelFormat ? cellLevelFormat(params.value) : params.value;
      }

      return metaLevelFormat ? metaLevelFormat(params.value) : params.value;
    };
  }

  if (metaLevelFormat != null) {
    return (params) => metaLevelFormat(params.value);
  }

  return undefined;
};

const emptyStyle = {};

/**
 * Construct a column's cell style function.
 */
const constructCellStyleFunction = (
  {
    cellLevelDataTypeField,
    rowLevelFormatField,
    rowLevelNullFormatField,
    cellLevelFormatField,
    cellLevelNullFormatField,
    columnLevelIsLink,
    cellLevelIsLinkField,
    getMetaLevelFormatObj,
    getMetaLevelNullFormatObj,
  }: {
    cellLevelDataTypeField?: string;
    rowLevelFormatField?: string;
    rowLevelNullFormatField?: string;
    cellLevelFormatField?: string;
    cellLevelNullFormatField?: string;
    columnLevelIsLink?: boolean;
    cellLevelIsLinkField?: string;
    getMetaLevelFormatObj: ((cellLevelDataType?: string) => FormatObj) &
      MemoizedFunction;
    getMetaLevelNullFormatObj: ((cellLevelDataType?: string) => FormatObj) &
      MemoizedFunction;
  },
  linkCellStyle: LinkCellStyle,
): CellStyleFunc | undefined => {
  const metaLevelStyle = cellStyleFunction(
    getMetaLevelFormatObj(undefined),
    getMetaLevelNullFormatObj(undefined),
  );

  if (
    cellLevelDataTypeField ||
    rowLevelFormatField ||
    rowLevelNullFormatField ||
    cellLevelFormatField ||
    cellLevelNullFormatField ||
    cellLevelIsLinkField
  ) {
    return (params) => {
      if (
        (cellLevelDataTypeField && params.data?.[cellLevelDataTypeField]) ||
        (rowLevelFormatField && params.data?.[rowLevelFormatField]) ||
        (rowLevelNullFormatField && params.data?.[rowLevelNullFormatField]) ||
        (cellLevelFormatField && params.data?.[cellLevelFormatField]) ||
        (cellLevelNullFormatField && params.data?.[cellLevelNullFormatField]) ||
        (cellLevelIsLinkField && params.data?.[cellLevelIsLinkField])
      ) {
        const formatObj = merge(
          {},
          cellLevelIsLinkField && params.data[cellLevelIsLinkField]
            ? linkCellStyle
            : {},
          getMetaLevelFormatObj(
            cellLevelDataTypeField
              ? params.data[cellLevelDataTypeField]
              : undefined,
          ),
          decodeFormat(
            rowLevelFormatField ? params.data[rowLevelFormatField] : undefined,
          ),
          decodeFormat(
            cellLevelFormatField
              ? params.data[cellLevelFormatField]
              : undefined,
          ),
        );

        const nullFormatObj = merge(
          {},
          cellLevelIsLinkField && params.data[cellLevelIsLinkField]
            ? linkCellStyle
            : {},
          getMetaLevelNullFormatObj(
            cellLevelDataTypeField
              ? params.data[cellLevelDataTypeField]
              : undefined,
          ),
          decodeFormat(
            rowLevelNullFormatField
              ? params.data[rowLevelNullFormatField]
              : undefined,
          ),
          decodeFormat(
            cellLevelNullFormatField
              ? params.data[cellLevelNullFormatField]
              : undefined,
          ),
        );

        const rowLevelStyle = cellStyleFunction(formatObj, nullFormatObj);

        return rowLevelStyle ? rowLevelStyle(params.value) : emptyStyle;
      }

      return metaLevelStyle ? metaLevelStyle(params.value) : emptyStyle;
    };
  }

  if (metaLevelStyle != null) {
    return (params) =>
      columnLevelIsLink
        ? { ...linkCellStyle, ...metaLevelStyle(params.value) }
        : metaLevelStyle(params.value);
  }

  return columnLevelIsLink ? () => linkCellStyle : undefined;
};

//function that saves the final coldefs and ag grid state in local storage
const persistUserGridState = (
  storageKey: string,
  { columnDefs, gridState }: UserGridState,
) => {
  const { columnOrder, columnSizing, sort } = gridState;
  const persistedColumnDefs: ColDef[] = [];
  const orderedColumnIds = columnOrder?.orderedColIds ?? [];

  const childColumnDefsMap: Map<string, ColDef[]> = new Map();
  let childColumnNames: (string | undefined)[] = [];

  // Populate childColumnDefsMap with child column definitions
  columnDefs.forEach((columnDef) => {
    if ((columnDef as ColGroupDef)?.children) {
      (columnDef as ColGroupDef)?.children?.forEach((childColumn) => {
        if (columnDef.field) {
          childColumnDefsMap.set(columnDef.field, [
            ...(childColumnDefsMap.get(columnDef.field) ?? []),
            childColumn,
          ]);
        }
      });
    }
  });

  // Collect all child column names
  childColumnDefsMap.forEach((childColumns: ColDef[]) => {
    childColumnNames = [
      ...childColumnNames,
      ...childColumns.map((child: ColDef) => child.field),
    ];
  });

  // Process ordered column IDs - to maintain column position based on user choice
  orderedColumnIds.forEach((columnId) => {
    const columnDef = columnDefs.find((def) => def.field === columnId);

    //user specified width
    const columnSize = columnSizing?.columnSizingModel.find(
      (size) => size.colId === columnId,
    );

    //user specified sort
    const columnSort = sort?.sortModel.find(
      (sortModel) => sortModel.colId === columnId,
    );

    //prepare coldef with final width/sort
    const columnDefinition = {
      ...columnDef,
      width: columnSize?.width,
      sort: columnSort?.sort,
      //overriding flex to force width based on user pref
      flex: columnDef?.width !== columnSize?.width ? 0 : columnSize?.flex,
    };
    if (
      columnDefinition &&
      columnDef?.field &&
      !childColumnNames.includes(columnId)
    ) {
      persistedColumnDefs.push(columnDefinition);
    }
  });

  // Update child column definitions in the original column definitions
  childColumnDefsMap.forEach((childColumns, parentField) => {
    const parentGroupDefIndex = columnDefs.findIndex(
      (def) => def.field === parentField,
    );
    const parentGroupDef =
      parentGroupDefIndex >= 0
        ? (columnDefs[parentGroupDefIndex] as ColGroupDef)
        : undefined;

    if (parentGroupDef?.children) {
      // prepare child columns coldefs
      parentGroupDef.children = parentGroupDef.children.map(
        (childDef: ColDef) => {
          const columnSize = columnSizing?.columnSizingModel.find(
            (size) => size.colId === childDef.field,
          );
          const columnSort = sort?.sortModel.find(
            (sortModel) => sortModel.colId === childDef.field,
          );
          return {
            ...childDef,
            width: columnSize?.width,
            sort: columnSort?.sort,
            //overriding flex to force width based on user pref
            flex: childDef?.width !== columnSize?.width ? 0 : columnSize?.flex,
          };
        },
      );
      persistedColumnDefs.splice(parentGroupDefIndex, 0, parentGroupDef);
    }
  });

  // Persist the updated grid state to local storage
  localStorage.setItem(
    storageKey,
    JSON.stringify({ columnDefs: persistedColumnDefs, gridState: gridState }),
  );
};

//function that determines proper column defs while considering original coldefs/overrides and return final gridstate and coldefs
const getUserGridState = (
  storageKey: string,
  columnDefinitions?: ColDef[],
  columnDefinitionOverrides?: ColDefOverride[] | undefined,
): UserGridState | undefined => {
  const storedData = localStorage.getItem(storageKey);
  // Return undefined if no stored state exists or no gridState property
  if (!storedData) {
    return undefined;
  }
  const parsedData = JSON.parse(storedData);
  if (!parsedData.gridState) {
    return undefined;
  }

  const storedGridState = parsedData as UserGridState;

  // Create Maps for faster lookups
  const columnDefMap = new Map(
    columnDefinitions?.map((col) => [col.field, col]),
  );
  const columnDefOverrideMap = new Map(
    columnDefinitionOverrides?.map((override) => [
      override.field,
      override.colDef,
    ]),
  );

  const colDefsExcluded =
    storedGridState?.columnDefs?.length > 0
      ? columnDefinitions
          ?.map((cd, indx) => {
            const field = storedGridState?.columnDefs?.find(
              (x) => x.field === cd.field,
            );
            if ((cd as ColGroupDef)?.children?.length > 0 && !!field) {
              const childColdefsStored = (field as ColGroupDef)
                ?.children as ColDef[];
              const providedChildColdefs = (cd as ColGroupDef)
                ?.children as ColDef[];

              const childColDefsToExclude = providedChildColdefs
                ?.map((ccd, cindx) => {
                  const childField = childColdefsStored?.find(
                    (x) => x.field === ccd.field,
                  );
                  return !childField
                    ? { coldef: ccd, index: cindx }
                    : undefined;
                })
                .filter((c) => !!c);

              //populate new child coldefs which are not already stored
              childColDefsToExclude?.forEach((exCd) => {
                childColdefsStored?.splice(exCd.index, 0, exCd.coldef);
              });
            }
            return !field ? { coldef: cd, index: indx } : undefined;
          })
          .filter((c) => !!c)
      : [];

  //populate new coldefs which are not already stored
  colDefsExcluded?.forEach((exCd) => {
    storedGridState?.columnDefs?.splice(exCd.index, 0, exCd.coldef);
  });

  storedGridState.columnDefs =
    storedGridState?.columnDefs
      ?.map((cd) => {
        const baseColumnDef = columnDefMap.get(cd.field);
        if (!baseColumnDef) return;
        const overrideColumnDef = columnDefOverrideMap.get(cd.field ?? "");
        const childColdefs = (cd as ColGroupDef)?.children as ColDef[];
        if (childColdefs?.length > 0) {
          const baseColdefChildren = (baseColumnDef as ColGroupDef)
            ?.children as ColDef[];
          (cd as ColGroupDef).children =
            (cd as ColGroupDef).children
              ?.map((bcd) => {
                const baseChildColumnDef = baseColdefChildren.find(
                  (ccd) => ccd.field === (bcd as ColDef)?.field,
                );
                if (!baseChildColumnDef) return;

                return {
                  ...baseChildColumnDef,
                  ...bcd,
                  headerName: baseChildColumnDef.headerName,
                };
              })
              .filter((cd) => !!cd) || [];
        }
        return {
          ...baseColumnDef,
          ...overrideColumnDef,
          ...cd,
          headerName: baseColumnDef.headerName,
        };
      })
      .filter((cd) => !!cd) || [];

  return storedGridState;
};

const resetUserGridState = (gridStateKey: string) => {
  localStorage.removeItem(gridStateKey);
};

